<?php
namespace App\Domain\Shops\Admin;use App\Domain\Shops\ShopCatalogValidator;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\CharacterLevelRequirement;use App\Models\Item;use App\Models\Shop;use App\Models\ShopOffer;use Carbon\CarbonImmutable;use Carbon\CarbonInterface;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class ShopOfferAdminService{private $validator;public function __construct(ShopCatalogValidator $validator){$this->validator=$validator;}public function save(Shop $shop,array $data,ShopOffer $offer=null){return DB::transaction(function()use($shop,$data,$offer){$lockedShop=Shop::whereKey($shop->id)->lockForUpdate()->firstOrFail();if($offer&&$offer->exists&&(int)$offer->shop_id!==(int)$lockedShop->id)throw new InvalidArgumentException('La oferta no pertenece a la Shop.');$item=Item::whereKey($data['item_id'])->lockForUpdate()->firstOrFail();$model=$offer&&$offer->exists?ShopOffer::whereKey($offer->id)->lockForUpdate()->firstOrFail():new ShopOffer(['shop_id'=>$lockedShop->id]);$normalized=$this->normalize($data);$model->fill($normalized);$this->validator->validateOffer($model);$this->validator->validateSellableItem($item,$model->category);if($model->required_character_level!==null&&(int)$model->required_character_level>(int)CharacterLevelRequirement::max('level'))throw new InvalidArgumentException('El nivel requerido no existe en la curva configurada.');$duplicate=ShopOffer::where('shop_id',$lockedShop->id)->where('item_id',$item->id)->when($model->exists,function($q)use($model){$q->where('id','<>',$model->id);})->exists();if($duplicate)throw new InvalidArgumentException('El Item ya tiene una oferta en esta Shop.');$model->save();return$model;},3);}public function activate(Shop $shop,ShopOffer $offer){return$this->status($shop,$offer,CatalogStatus::ACTIVE);}public function deactivate(Shop $shop,ShopOffer $offer){return$this->status($shop,$offer,CatalogStatus::INACTIVE);}private function status(Shop $shop,ShopOffer $offer,$status){$data=$offer->only(['item_id','category','quantity','gold_price','visibility','stock_limit','stock_remaining','purchase_limit_per_character','required_character_level','sort_order']);$data['starts_at']=$offer->starts_at;$data['ends_at']=$offer->ends_at;$data['status']=$status;$data['stock_mode']=$offer->stock_limit===null?'unlimited':'limited';return$this->save($shop,$data,$offer);}private function normalize(array $data){foreach(['quantity','gold_price','stock_limit','stock_remaining','purchase_limit_per_character','required_character_level','sort_order']as$field)$data[$field]=$this->integer(isset($data[$field])?$data[$field]:null,in_array($field,['stock_limit','stock_remaining','purchase_limit_per_character','required_character_level'],true));if(isset($data['stock_mode'])&&$data['stock_mode']==='unlimited'){$data['stock_limit']=null;$data['stock_remaining']=null;}unset($data['stock_mode']);foreach(['starts_at','ends_at']as$field)$data[$field]=$this->date(isset($data[$field])?$data[$field]:null);return$data;}private function integer($value,$nullable){if($nullable&&($value===null||$value===''))return null;if(is_int($value)&&$value>=0)return$value;if(!is_string($value)||!preg_match('/^(0|[1-9][0-9]*)$/',$value)||strlen($value)>strlen((string)PHP_INT_MAX)||(strlen($value)===strlen((string)PHP_INT_MAX)&&strcmp($value,(string)PHP_INT_MAX)>0))throw new InvalidArgumentException('Valor numÃ©rico invÃ¡lido.');return(int)$value;}private function date($value){if($value===null||$value==='')return null;if($value instanceof CarbonInterface)return CarbonImmutable::instance($value);return CarbonImmutable::createFromFormat('Y-m-d\TH:i',(string)$value,'UTC');}}
